import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

function PostPage({ currentUser }) {
  const { id } = useParams(); // post id from URL
  const [post, setPost] = useState(null);
  const [replyText, setReplyText] = useState("");

  // Fetch post (increments views automatically in backend)
  const fetchPost = async () => {
    try {
      const res = await fetch(`/api/posts/${id}`);
      const data = await res.json();
      setPost(data);
    } catch (err) {
      console.error("Error fetching post:", err);
    }
  };

  useEffect(() => {
    fetchPost();
    // eslint-disable-next-line
  }, [id]);

  // Handle reply submit
  const handleReply = async (e) => {
    e.preventDefault();
    if (!replyText.trim()) return;

    try {
      await fetch(`/api/posts/${id}/reply`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId: currentUser._id, text: replyText }),
      });
      setReplyText("");
      fetchPost(); // refresh post to show new reply
    } catch (err) {
      console.error("Error adding reply:", err);
    }
  };

  if (!post) return <p>Loading post...</p>;

  return (
    <div className="container mx-auto p-6">
      {/* Post Content */}
      <div className="bg-white p-6 rounded-2xl shadow mb-6">
        <h1 className="text-2xl font-bold mb-2">{post.title}</h1>
        <p className="text-gray-700 mb-4">{post.content}</p>
        <div className="text-sm text-gray-500">
          By <span className="font-medium">{post.author?.username}</span> •{" "}
          {new Date(post.createdAt).toLocaleString()} • {post.views} views
        </div>
      </div>

      {/* Replies Section */}
      <div className="bg-gray-50 p-6 rounded-2xl shadow mb-6">
        <h2 className="text-xl font-semibold mb-4">
          Replies ({post.replies.length})
        </h2>

        {post.replies.length === 0 ? (
          <p className="text-gray-500">No replies yet. Be the first!</p>
        ) : (
          post.replies.map((reply, idx) => (
            <div
              key={idx}
              className="border-b border-gray-200 py-2 last:border-none"
            >
              <p className="text-gray-800">{reply.text}</p>
              <div className="text-sm text-gray-500">
                By {reply.user?.username || "Anonymous"} •{" "}
                {new Date(reply.createdAt).toLocaleString()}
              </div>
            </div>
          ))
        )}
      </div>

      {/* Reply Form */}
      {currentUser ? (
        <form
          onSubmit={handleReply}
          className="bg-white p-6 rounded-2xl shadow"
        >
          <h3 className="text-lg font-semibold mb-2">Add a reply</h3>
          <textarea
            className="w-full p-2 border rounded-lg mb-3"
            rows="3"
            value={replyText}
            onChange={(e) => setReplyText(e.target.value)}
            placeholder="Write your reply..."
          />
          <button
            type="submit"
            className="bg-purple-600 text-white px-4 py-2 rounded-xl hover:bg-purple-700"
          >
            Post Reply
          </button>
        </form>
      ) : (
        <p className="text-gray-600">
          Please <span className="text-purple-600">log in</span> to reply.
        </p>
      )}
    </div>
  );
}

export default Forum;
